    TextStyleDelta.delta(
      color: colors.primaryForeground,
    ),
  ),]),
            // selected input text color
            contentTextStyle: FVariants(
              const TextStyle(),
              variants: {
                [FTextFieldVariantConstraint.not(.linux)]: TextStyle(
                  color: colors.primaryForeground
                )
              }
            ),
            
            counterTextStyle: FVariants(
              const TextStyle(),
              variants: {
                []: TextStyle(
                  color: colors.destructive
                ),
                [FTextFieldVariantConstraint.not(.linux)]: TextStyle(
