              }
            ),

            errorTextStyle: FVariants(
              const TextStyle(),
              variants: {
                []: TextStyle(
                  color: colors.destructive
                ),
                [FFormFieldErrorVariantConstraint.not(.linux)]: TextStyle(
                  color: colors.destructive
                )
              }
            ),

            labelTextStyle: FVariants(
                const TextStyle(),
                variants: {
                  []: TextStyle(
                    color: colors.primaryForeground
                  ),
                  [FFormFieldVariantConstraint.not(.linux)]: TextStyle(
                    color: colors.primaryForeground
                  )
                }
              ),

            descriptionTextStyle: FVariants(
              const TextStyle(),
              variants: {
                []: TextStyle(
                  color: colors.error
                ),
                [FFormFieldVariantConstraint.not(.linux)]: TextStyle(
                  color: colors.error
                )
              }
            ),

            color: FVariants(
              colors.secondaryForeground,
                variants: {
                []: colors.secondaryForeground
                }
            ),
          ),
      ),
]),

  contentStyle: .delta(
      
      scrollHandleStyle: .delta(
        background: Colors.blueAccent
      ),

      decoration: .boxDelta(
        color: colors.secondaryForeground
      ),

      sectionStyle: .delta(
        
        labelTextStyle: FVariants(
          const TextStyle(), variants: {
            [FSelectSectionVariantConstraint.not(.linux)]: TextStyle(
              color: colors.secondary,
            )
          }),
        itemStyle: .delta(
          rawContentStyle: .delta(
            childTextStyle: FVariants(
              const TextStyle(),
              variants: {
                []: TextStyle(color: colors.destructive),
                [FTappableVariantConstraint.not(.linux)]: TextStyle(
                  color: colors.destructive
                ),
                
              })
          ),
          contentStyle: FItemContentStyleDelta.delta(
              titleTextStyle: FVariants(
          const TextStyle(),
          variants: {
            []: TextStyle(
              color: colors.primaryForeground
            ),
            [FTappableVariantConstraint.focused]: TextStyle(
              color: colors.primaryForeground
